INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('generalpolice-8b7f1efc-moex-00012', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-13504c0c', 'sub-generalpolice-8b7f1efc-03', NULL, 'single_choice', '「一座臨水的扇面小亭，每當夜深人靜，清風徐來，明月當空，水天上下相映，好 一派清淨幽寂，小亭以蘇軾詞中『與誰同坐，明月清風我』句，取名為『與誰同坐 軒』。」 根據上文，此亭取名「與誰同坐軒」的原因為何？', '["此亭清幽能讓人興起飄飄欲仙之感", "明月與清風正好是臨水小亭的特色", "感念蘇軾的儒雅風采渴望與其同坐", "美景當前總讓人傷嘆無知己可共賞"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00013', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-13504c0c', 'sub-generalpolice-8b7f1efc-03', NULL, 'single_choice', '「尚樸的日本茶道愛好者早在數百年前便推崇侘寂之道，珍視器皿製造過程中無心 造就的不完美，追求『碗碗有瑕，各瑕不同』的美學，認為每個茶碗的獨特缺陷恰 好賦予其無法模仿的『個性』；宋代鑑賞家與文人認為開片（瓷器釉面自然龜裂的 現象）最符合審美原則，因為其效果『非人工做作，而是從材質與技法之中自然生 發而成。』」 根據上文，下列選項何者正確？', '["日本茶道推崇的侘寂之道即宋代的品茶審美之道", "侘寂之道強調簡樸美學，格外注重器皿製造材質", "宋代瓷器製造技術尚未成熟，才會經常出現「開片」效果", "日本茶道愛好者與宋代鑑賞家均注重難以複製的缺陷之美"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00014', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-13504c0c', 'sub-generalpolice-8b7f1efc-03', NULL, 'single_choice', '「為了獲得更漂亮的羽毛而落去原有的羽毛，這有點像是學著每年自我更新，儘管 必須歷經一段艱困的時期才能達成。身為有別於鳥的人類，我們雖然會掉毛髮，但 並不了解這些換羽的階段——然而對我們人類來說，有時也必須換羽。在某些重大 的生命時刻——為愛心碎、哀悼、失業、遷居之際，我們必須改頭換面、變換衣著 或髮型以及生活作息。」 根據上文，下列何者最適合用來解釋人類的「換羽」？', '["調整後重新出發", "挑戰體能的極限", "思考後審慎行動", "把握當下的時光"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00015', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-13504c0c', 'sub-generalpolice-8b7f1efc-03', NULL, 'single_choice', '「『形破』（Deformation）是對既定的形的突破，要說是追求自由的人們所表現出 的念想也可以；也可以說是『未定型』或『未成形』，我想以容易理解的『奇數之 美』來稱之。『奇』並不是奇怪的意思，是與『偶』相對的『奇』，或『不完整』。」 下列選項，何者最貼近上文的觀點？', '["奇數的美，往往比偶數的美，來得更容易被看見", "勇於打破形式的框架限制，展現創作的自由意志", "形破，因為還不完整，故能取得最大的想像空間", "創作自由，就是要不斷地推陳出新，表現新形式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00016', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-13504c0c', 'sub-generalpolice-8b7f1efc-03', NULL, 'single_choice', '「2022 年，聊天機器人 ChatGPT 的出現引領了全球人工智慧的熱潮，但也帶來了 人們對就業和倫理的擔憂。關於就業，研究表明，在未來幾十年內，真正被取代的 工作僅占所有工作的10％左右。並非所有工作都會被完全自動化，而是某些特定任 務會被自動化。重要的是，我們需要關注人們是否具備與機器協作的技能，並提供 技能再造和適應新職場的支持。關於倫理問題，面對強大的人工智慧系統時，需要 思考如何合理應用它，避免不良利用。如何制定合理的使用原則，確保訓練和應用 符合實際需求。同時，也要關注可能的誤用，包括無意的落差和有意的濫用。解決 這些就業和倫理問題，需要的不僅是電腦工程專家，還需要涉及多個領域的專家， 如社會科學家、倫理學者和哲學家等。」 根據上文，下列選項何者最符合文意？', '["解決就業和倫理問題，端賴全球電腦工程專家的共同努力", "研究表明，在未來幾十年內，所有工作都會被完全自動化取代", "人工智慧帶來就業和倫理的擔憂，需要關注技能再造和適應新職場", "強大人工智慧系統的應用，需要遵循傳統的使用原則，以防止不良利用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00017', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-13504c0c', 'sub-generalpolice-8b7f1efc-03', NULL, 'single_choice', '「大企業為什麼凡事都得曠日廢時？主要是官僚作風的無形掣肘——每件事都必 須按照規定與流程完成。許多企業主管表示希望從官僚作風轉變為『菁英精神』， 置人才與構想於一切之上。但事實證明，菁英精神可以跟官僚作風一樣拖拖拉拉， 一樣著眼於內部。我們在最古老的菁英體系——大學——中工作，儘管我們痛恨規 則，卻熱愛事事針鋒相對。所以，你需要的是著重於行動。在實務上，簡化公司正 式流程、減少跨部門委員會的數量與規模，以靈活、敏捷的小型團隊模式取而代之； 這些團隊獲得授權，可以快速直接因應顧客需求。打比方，你不妨將這些團隊想像 成軍方派入敵區作戰的特殊部隊。」 根據上文，下列敘述何者正確？', '["官僚作風可以靈活地省略各種規定與流程", "菁英精神重視人才與構想，而且行動迅速", "菁英精神未必能克服官僚作風在處理事務上的效率問題", "團體組織更見效率，流程簡化時擴大跨部會委員會規模"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:33+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "301", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('generalpolice-8b7f1efc-moex-00018', 'generalpolice-8b7f1efc', 'generalpolice-8b7f1efc-moex-114-0b2477b6', 'sub-generalpolice-8b7f1efc-04', NULL, 'essay', '成長、維持與失去是三個動態且交互影響的規則，試說明如何以此三個
